var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"한 달 후, 노스텔지어 공방","JPN":"1か月後、工房ノスタルジア","ENG":"One month later, Nostalgia Workshop","TWN":"一個月後，追舊工作室"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"KS-7, 준위험 침식지대","JPN":"KS-7、準危険侵食地帯","ENG":"KS-7, Semi-hazardous Corrupted Area","TWN":"KS-7，準危險侵蝕地帶"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"거점으로부터 13km 지점, 장승바위산","JPN":"拠点から13km地点、道祖神岩山","ENG":"13 km from base, Mt. Totem Rock","TWN":"距離據點 13 公里處，長承岩山"},"stage":{"bg":"BLACK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"확인 끝났다. 이 산도 감지되는 게 전혀 없군.","JPN":"確認完了。この山も何も感知されないな。","ENG":"Sweep's done. This mountain's clean too. Not a single trace.","TWN":"確認結束。這座山也沒有任何感應。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이쪽도 침식파 제로. 통신에 노이즈조차 하나 안 끼어.","JPN":"こっちも侵食波ゼロ。通信にノイズの一つも乗らないよ。","ENG":"Nothing here too. Not even a blip of Corruption rays. Comms are totally clear.","TWN":"這邊侵蝕波也是零，連通訊都沒有雜訊。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…다들 고생했네.","JPN":"……2人ともご苦労だった。","ENG":"…Good work, both of you.","TWN":"…大家辛苦了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"해가 저물고 있으니, 이만 모이도록 하지.","JPN":"そろそろ日が暮れる。集合するとしよう。","ENG":"The sun's setting. Let's wrap it up.","TWN":"天快黑了，我們集合吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"흐음- 먹비가 안 내린 지도 벌써 한 달짼가?","JPN":"ふーん……墨雨が降らなくなってもう1か月かな。","ENG":"Hmm… Has it really been a month since we last saw the Ink Rain?","TWN":"嗯，已經一個月沒下墨雨了吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"평화로운 게 싫진 않지만… 매번 허탕만 치는 것도 좀 지겹네.","JPN":"平和なのは嫌いじゃないけど……毎回無駄足を踏むのも飽きてきたね。","ENG":"I'm not complaining about the peace… but this constant dry spell's getting old.","TWN":"雖然沒什麼事蠻好的…但每次都白跑一趟也有點煩。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"우리가 너무 열심히 치우고 다녀서 KS 일대가 전부 청정구역이 돼 버린 건 아니겠지?","JPN":"まさか私たちが頑張りすぎたせいで、KS一帯が全部綺麗になったんじゃない？","ENG":"What if we've been too good at cleaning up? Maybe the entire KS region's turned into a safe zone.","TWN":"會不會是我們太認真清理，把KS一帶都變成了淨化區？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"서생, 당신 생각은 어때? 난 저 녀석 얘기도 아주 터무니없진 않은 것 같은데.","JPN":"ショウ、お前の意見はどうだ？　案外、見当違いでもないとは思わないか。","ENG":"What do you think, Seosaeng? I don't think her theory's completely off the mark.","TWN":"書生，你覺得呢？我覺得她這話也不是完全沒道理。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…그렇군.","JPN":"……そうだな。","ENG":"…I see.","TWN":"…說得也是。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"침식파가 지력처럼 축적된 에너지라 가정한다면, 그동안 우리가 그 에너지를 너무 끌어다 쓴 것이 침식주기에 영향을 줬을 지도 모르지.","JPN":"侵食波が地力のように蓄積されたエネルギーだと仮定すると、今まで我らがそのエネルギーを使いすぎてしまったことにより、侵食周期に影響を及ぼしたのかもしれんな。","ENG":"If Corruption rays are like soil-bound energy, it's possible we've drawn out too much of it ourselves and disrupted the cycle.","TWN":"如果將侵蝕波假設為像地力般累積的能量，那麼這段時間我們過度汲取該能量，或許已經對侵蝕週期造成影響。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"인상 좀 펴, 사부. 그러다 늙겠다.","JPN":"眉間に皺が寄ってるよ、師匠。そんなんじゃすぐ老けちゃうんだから。","ENG":"Quit frowning, Master. You'll age even faster.","TWN":"別愁眉苦臉的，師父。會變老。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"신경 쓰이게 했다면 미안하네.","JPN":"……ああ、気を遣わせてしまったならすまない。","ENG":"Apologies if I made you worry.","TWN":"害你擔心，很抱歉。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"집에 가자. 계란찜 해줄게.","JPN":"帰ろう、茶碗蒸し作ってあげる。","ENG":"Let's head home. I'll make you steamed eggs.","TWN":"回家吧，我做蒸蛋給你吃。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"맞다. 계란 다 떨어졌지.","JPN":"あ、そういえば卵切らしてたんだった。","ENG":"Oh, right. We're out of eggs.","TWN":"對吼，雞蛋用完了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"고기도 조금 밖에 안 남았군.","JPN":"肉もあと少ししか残ってないな。","ENG":"And nearly out of meat too.","TWN":"肉也沒剩多少。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그럴 만도 하네. 요즘 계속 산만 뒤지고 다녔으니까.","JPN":"まあ、最近はずっと山ばかり探し回ってたしね。","ENG":"Figures. We've been rummaging through mountains all week.","TWN":"也難怪，最近我們一直在山上找東西。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"장은 내가 봐오지. 두 사람은 쉬고 있게나.","JPN":"買い物は某が行って来よう。2人は休んでいたまえ。","ENG":"I'll go grocery shopping. You two take it easy.","TWN":"我去買菜吧，你們兩個休息一下。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이 밤중에 도시까지 가려고? 위험하지 않아?","JPN":"こんな夜中に都市まで行くの？　危険じゃない？","ENG":"You're heading into the city at this hour? Isn't that dangerous?","TWN":"這麼晚還要去城裡？會不會太危險？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"달이 밝으니 걱정 말게.","JPN":"心配には及ばない。月が明るいからな。","ENG":"The moon's bright tonight. No need to worry.","TWN":"月光很亮，別擔心。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"오늘 같은 날 계란찜을 먹지 못하면 편히 못 잠들 것 같아서 말이야.","JPN":"今日のような日に茶碗蒸しが食べられないとなれば、ぐっすり眠れない気がするのだ。","ENG":"And frankly, I don't think I'll sleep well without that steamed egg dish.","TWN":"今天要是吃不到蒸蛋，我會睡不著的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"푸훗, 뭐야아. 계란찜 못 먹으면 못 잔다니. 귀엽네.","JPN":"ぷっ、何それ～。茶碗蒸しが食べられないと眠れないんだって～かわいい。","ENG":"Pfft, wow. Can't sleep without steamed eggs? That's kinda cute.","TWN":"噗，什麼嘛。吃不到蒸蛋就睡不著。真可愛。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"누가 귀엽다고?","JPN":"可愛い？　誰が？","ENG":"Cute? Who are you calling cute?","TWN":"誰可愛？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"크흠, 얼른 다녀와. 청소라도 하면서 기다릴게.","JPN":"ゴホン、早くいって来て。掃除でもしながら待ってるよ。","ENG":"Ahem, just hurry back. I'll clean up while you're out.","TWN":"咳咳。快去快回，我先回家邊打掃邊等。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"특별히 더 필요한 것이라도 있나?","JPN":"他に必要なものはあるか？","ENG":"Is there anything else we need while I'm at it?","TWN":"還有沒有其他需要的東西？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아, 그렇지.","JPN":"あ、そうだ。","ENG":"Ah, right.","TWN":"有！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"간만의 야식이니까, 라면도 잔뜩 사와버려!","JPN":"久しぶりの夜食だから、インスタント麺もいっぱい買ってきて！","ENG":"It's been ages since we had a midnight snack, so could you grab a bunch of instant noodles too?","TWN":"難得的宵夜，多買點泡麵回來！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"혼자서 장을 보겠다니. 유별나게 부지런한 날이군.","JPN":"一人で買い物とは、いつになくマメに働くな。","ENG":"Doing the shopping solo? He's oddly diligent today.","TWN":"竟然一個人去買菜，今天還真是特別勤快。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"우리가 산 오를 동안 밑에서 편하게 장비만 만졌으니까, 나름 공평하지 않아?","JPN":"私たちが山に登ってる間、下で装備だけいじって楽してたから公平なんじゃない？","ENG":"Hey, while we were hiking up the mountain, he was chilling down here fiddling with gear. It balances out.","TWN":"我們在爬山的時候，他在下面輕鬆地摸摸裝備，這也算公平吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"청소나 하자. 거점 옮긴 지 얼마 안 돼서 아직 못 치운 게 산더미잖아.","JPN":"早く掃除しよう。拠点移ったばっかで、まだ片付いてないものが山ほどあるよ。","ENG":"Let's clean up. We just moved our base and there's still a mountain of unpacked stuff.","TWN":"還是打掃吧。我們才搬家沒多久，還有很多東西沒整理。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그러고보니…","JPN":"そういえば……","ENG":"Now that you mention it…","TWN":"說起來…"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"저 큰 고철덩이는 뭐길래 계속 창고에 두는 거지?","JPN":"ずっと倉庫に置いてある、あのデカい鉄の塊は何なんだ？","ENG":"What's with that big hunk of scrap metal still sitting in the storage?","TWN":"那一大塊廢鐵是什麼？為什麼一直放在倉庫裡？"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"이삿짐 옮길 때 쓰는 건 봤지만, 그런 시시한 목적으로 만든 건 아닌 것 같은데.","JPN":"引っ越しの荷物を運ぶ時使っていたが、そんなくだらない目的のために作ったものではないだろう。","ENG":"I saw you using it during the move, but I doubt it was built for something that mundane.","TWN":"我看過它用來搬家，但那種小事應該不是它真正的用途吧。"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부랑 내가 만들던 <color=#ffd34c>이동요새</color>라는 거야.","JPN":"師匠と私で作ってた、<color=#ffd34c>移動要塞</color>ってやつだよ。","ENG":"That's our <color=#ffd34c>moving fortress</color> that Master and I was making.","TWN":"那是我和師父一起做的移動要塞。"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"먹비를 피해 거점을 계속 옮겨 다니는 대신 움직이는 집을 만들려 했었거든.","JPN":"墨雨を避けて拠点を頻繁に移動するんじゃなくて、そもそも動く家を作ろうとしてたんだ。","ENG":"We were building a moving home instead of constantly relocating our base to avoid the Ink Rain.","TWN":"我們原本不想因為要躲避墨雨而搬家，所以才想說造一個能移動的房子。"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"요새라기엔 많이 빈약해 보이는군.","JPN":"要塞の割には随分みすぼらしいな。","ENG":"A bit flimsy to call it a fortress.","TWN":"這看起來也太不堪一擊，不像個要塞。"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"미완성이니까. 원인은 자금 부족.","JPN":"未完成だからね。原因は資金不足。","ENG":"It's unfinished. Due to budget issues.","TWN":"還沒完成啦。因為資金不足。"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"자금이라면… 혹시 내 급여 때문에 부족한 건가?","JPN":"……資金……もしかして、私の給料のせいなのか？","ENG":"Budget, huh… Don't tell me my paycheck's the reason it stalled.","TWN":"資金…難道是因為我的工資嗎？"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아핫, 어르신도 귀여운 면이 있었네. 저 큰 기계가 어르신 월급이랑 맞먹을 거라 생각하다니-","JPN":"あははっ、おばあさんも可愛いところあるね。あんなデカい機械の製作費がおばあさんの給料と同じくらいだと思うなんて～","ENG":"Ahaha, didn't know you had a cute side, granny. You really think that monster of a machine costs the same as your salary?","TWN":"哈哈，你也蠻可愛的嘛。竟然會覺得那台巨大機器的費用和你的薪水差不多。"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"놀리는 거냐?","JPN":"バカにしているのか？","ENG":"Are you mocking me?","TWN":"你是在嘲笑我嗎？"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"돈도 문제지만 사실 진짜 문제는 필요한 소재를 구할 데가 마땅치 않다는 거야.","JPN":"お金もだけど、根本的な問題は、必要な素材の入手先がないってことなの。","ENG":"Money's one thing, but honestly the real problem's sourcing the parts.","TWN":"錢是個問題，但真正的問題是，需要的材料根本沒地方買。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"볼래? 이게 사부가 예전에 그린 설계도거든.","JPN":"見る？　これは師匠が以前書いた設計図なんだけど。","ENG":"Wanna see? This is the blueprint Master sketched a while back.","TWN":"要看看嗎？這是師父以前畫的設計圖。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"대충 봐도 뭐가 문제인지 알겠지?","JPN":"パッと見ても何が問題か分かるでしょ？","ENG":"Even a glance tells you what the issues are, right?","TWN":"你隨便看看也知道問題在哪裡吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"내가 설계도 보는 법을 알 거라 생각하나?","JPN":"私に、設計図の見方が分かると思ってるのか？","ENG":"You think I know how to read blueprints?","TWN":"你覺得我會看得懂設計圖嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"복층 포갑판 구조에 관리국 T2 규격에 준하는 대포만 아홉 정이 들어가.","JPN":"複層の砲列甲板構造に、管理局のT2規格にあたる大砲だけで9門が要るの。","ENG":"Double-deck armor plating, nine cannons built to Administration T2 specs…","TWN":"雙層裝甲結構，還搭載符合管理局T2標準的九門大砲。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"대형 침식체를 격침시킬 수 있는 초장거리 이온캐논까지 달려있지.","JPN":"大型侵食体を撃沈させられる、超長距離イオンキャノンまでついてる。","ENG":"And even a long-range ion cannon strong enough to take down a large C.O.","TWN":"甚至還有能擊沉大型侵蝕體的超長距離離子加農砲。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_HATE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"집이 아니라 최종병기라도 만들 셈이었나 보군.","JPN":"家じゃなくて最終兵器でも作るつもりだったようだな。","ENG":"Sounds less like a house and more like the ultimate weapon.","TWN":"這不是要造房子，是要造終極兵器吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"내 말이- 이런 장비는 돈이 있어도 못 구해.","JPN":"まったくだよ～こんな装備、お金があっても手に入らないって。","ENG":"That's what I said. Stuff like this, you can't just buy.","TWN":"就是說，這種裝備有錢也買不到。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"누가 바닥에 흘린 차원함선이라도 주우면 모를까. 애들 망상 낙서나 다름없다고.","JPN":"誰かが落とした次元艦船を拾いでもしなければ、これは子どもの妄想みたいなもんだよ。","ENG":"Unless someone drops a dimensional ship at our feet, it's nothing more than a pipe dream.","TWN":"除非在地上撿到一艘次元建船，否則這根本就是小孩子的天馬行空。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저것도 버리지만 않고 있을 뿐이지. 손도 못 대서 1년 전이랑 상태는 똑같아.","JPN":"あれもまだ捨ててないだけで、まったく手つかずで1年前と同じ状態なの。","ENG":"We haven't touched it in over a year. Just haven't gotten around to scrapping it either.","TWN":"這東西也只是沒被丟掉。一年來，連動都沒動過。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"저걸 버리지 못하는 건 서생의 고집인가?","JPN":"捨てられないのは、ショウの意地なのか？","ENG":"So it's Seosaeng's stubbornness that's keeping it around?","TWN":"書生之所以沒丟掉它，是因為他固執嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"음… 아니. 사부는 몇 번이나 해체하려고 했어.","JPN":"うーん……違うかな。師匠は何度も解体しようとしたんだけど。","ENG":"Mmm… nope. He's tried to dismantle it several times.","TWN":"嗯…不是。師父好幾次都想拆掉它。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그때마다 내가 말렸고.","JPN":"そのたびに私が止めたの。","ENG":"And I'm the one who stopped him.","TWN":"但每次都被我攔住。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"왜지?","JPN":"なぜだ？","ENG":"Why?","TWN":"為什麼？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"낭만있잖아. 침식된 땅을 종횡무진하는 이동요새이자 최종병기.","JPN":"ロマンがあるでしょ。侵食された大地を縦横無尽に駆ける移動要塞かつ最終兵器。","ENG":"It's got charm, y'know? A roaming fortress-slash-ultimate weapon that cuts across Corrupted lands.","TWN":"這是夢想呀。一個能在被侵蝕的土地上縱橫的移動要塞，也是終極兵器。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이사 갈 때 짐 싣기도 좋고 말이야.","JPN":"引っ越す時は荷物も運べるしね。","ENG":"And it's perfect for hauling stuff when we move too.","TWN":"搬家的時候還能用來載東西。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"낭만이라. 네가 그런 것에 관심 있는 줄 몰랐군.","JPN":"ロマンか。お前がそんなものに興味があるとは知らなかったな。","ENG":"Didn't peg you as someone who gets sentimental.","TWN":"夢想嗎，沒想到你對這種東西有興趣。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그러게.","JPN":"そうだね。","ENG":"Oh well.","TWN":"對呀。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"같이 지내다 보면 닮는다- 뭐 그런 건가 봐.","JPN":"一緒に居ると似てくる、そういうことなのかな。","ENG":"I guess it rubs off on you when you spend time with someone long enough.","TWN":"朝夕相處就會變得越來越像，應該就是這麼回事。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"달빛이 흐리군. 안개가 짙어졌어.","JPN":"月明かりが弱いな。霧が濃くなってきた。","ENG":"The moonlight's dimming. And the fog's getting thick.","TWN":"月色很暗，霧也變濃了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…이쯤에서 숲길을 벗어나야 하는데, 이상하군.","JPN":"……そろそろ森を抜ける頃合いだが、おかしい。","ENG":"…Should be about time to leave the forest path, and yet, it's strange.","TWN":"…開到現在應該要離開森林了吧，真奇怪。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"거기 누구요?","JPN":"そこに誰かいるのか？","ENG":"Who's there?","TWN":"你是誰？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"혹여 길이라도 잃었나?","JPN":"道にでも迷ったのか？","ENG":"Did you lose your way, perhaps?","TWN":"迷路了嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_CA_QM_SILHOUETTE","text":{"KOREA":"아뇨.","JPN":"いいえ。","ENG":"No.","TWN":"不是。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_CA_QM_SILHOUETTE","text":{"KOREA":"기슭으로 숨어든 맹수를 찾고 있었습니다.","JPN":"麓に隠れている猛獣を探していました。","ENG":"I'm looking for a beast that slunk down to the ridge.","TWN":"我在找躲在山腳的猛獸。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"맹수라고? 왜 그런 것을 찾고 있지?","JPN":"猛獣？　なぜそのようなものを探している？","ENG":"A beast? And why's that?","TWN":"猛獸？你為什麼要找猛獸？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_CA_QM_SILHOUETTE","text":{"KOREA":"그 맹수는 많은 사람을 물어 죽인 짐승이니, 사람이 거두어야죠.","JPN":"あの猛獣は多くの人を噛み殺したケモノです。人間の手で始末しないと。","ENG":"It's a beast that's mauled and killed many. It's up to people like us to put it down.","TWN":"那隻猛獸咬死很多人，當然要來處理一下。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_QM_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"사냥꾼인가? 무기는 들고 있지 않은 것 같은데.","JPN":"そなたは狩人か？　武器を持っているようには見えんが。","ENG":"A hunter, then? You don't seem to be carrying any weapons.","TWN":"你是獵人嗎？但你沒拿武器。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_QM_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"예전의 이곳은 어땠을지 모르나, 지난 수 년 간 이 산에 머물면서 맹수는 본 적이 없다네.","JPN":"昔のここはどうだったか分からんが、ここ数年間この山に滞在していて、猛獣を見たことは一度もない。","ENG":"I can't speak to the past, but I've spent years on this mountain and never seen a beast.","TWN":"雖然不知道以前這裡是怎樣，但我在這座山待了幾年，從來沒見過猛獸。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_QM_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_CA_QM_SILHOUETTE","text":{"KOREA":"그렇군요.","JPN":"そうですか。","ENG":"I see.","TWN":"是嗎。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_QM_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_CA_QM_SILHOUETTE","text":{"KOREA":"그래도 조심하세요. 녀석은 교활해서 쉽게 그 모습을 드러내지 않거든요.","JPN":"それでも気をつけてください。やつは狡猾で、なかなか姿を表すことがないんです。","ENG":"Still, be careful. It's sly and rarely shows itself.","TWN":"不過還是小心點。那傢伙很狡猾，不會輕易現身。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_QM_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_CA_QM_SILHOUETTE","text":{"KOREA":"생각지도 못한 방식으로 우리의 목덜미를 노리고 있을지도 모르죠.","JPN":"思いもしなかったやり方で、僕らの首を狙っているかもしれませんよ。","ENG":"Might just strike us when we least expect it.","TWN":"說不定會用出人意料的方式咬住我們的後頸。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_CA_QM_SILHOUETTE","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이런 음산한 분위기에 잘도 그런 무서운 농담을 던지는군.","JPN":"こんな陰鬱な場所でよくそのような冗談が言えたものだ。","ENG":"You've got quite the gift for ominous jokes in this spooky atmosphere.","TWN":"在這種陰森的氣氛下，你竟然還說出這種恐怖的笑話。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"잠깐, 기다리게.","JPN":"待ちたまえ。","ENG":"Wait, hold on.","TWN":"等等，等一下。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"도로는 반대쪽이야. 그쪽으로 가면 더 깊은 숲일 뿐…","JPN":"道路は反対側だ。そちらに行くと森の更に奥へ……","ENG":"The road's the other way. That path only leads deeper into the woods–","TWN":"那邊是反方向。那邊只會進入更深的森林…"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…들은 체도 않고 가버렸군.","JPN":"……聞く耳持たずに行ってしまったか。","ENG":"…He just left.","TWN":"…頭也不回地走掉了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이보게. 들리면 기척이라도 내게나.","JPN":"おい、聞こえているなら何か反応してくれ。","ENG":"Hey. If you can hear me, at least make a sound.","TWN":"先生，有聽見的話就出個聲吧。"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"분명 이쪽으로 향했을 터…","JPN":"間違いなくこの方向へ向かったはず……","ENG":"He definitely went this way…","TWN":"明明是往這邊走的…"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…음?!","JPN":"……うむ！？","ENG":"…Mm?!","TWN":"…嗯？！"},"stage":{"bg":"DREAM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"누군가 파둔 구멍인가? 제법 깊은데.","JPN":"誰かが掘った穴か？　かなり深いな。","ENG":"Did someone dig this pit? It's deep.","TWN":"是誰挖的洞嗎？還蠻深的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부- 거긴 괜찮아? 밖에 안개가 많이 심해서 연락해봤어.","JPN":"師匠～そっちは大丈夫？　外を見たら霧がすごくて連絡したの。","ENG":"Master, are you okay over there? The fog's really thick, so I figured I'd check in.","TWN":"師父，你還好嗎？外面霧好濃，我打給你確認一下你沒事吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L35_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"지금 장 보고 있지?","JPN":"今買い物中だよね？","ENG":"You're out shopping, right?","TWN":"你在買菜吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"안 서둘러도 되니까, 날씨 괜찮아질 때까지 여관에서 쉬다 오는 게 어때?","JPN":"急がなくていいから一旦宿に泊まって、天気がよくなったら帰ってくるのはどう？","ENG":"No need to rush. Why not wait out the weather at an inn?","TWN":"不用急，要不要找個地方休息一下，等天氣好一點再回來？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"여관에서 쉬고 싶은 마음은 굴뚝 같지만… 차질이 생겼네.","JPN":"宿で休みたい気持ちは山々だが……問題が生じた。","ENG":"Believe me, I'd love to rest in a warm inn… But I've hit a snag.","TWN":"我是很想找個地方休息…但現在有點狀況。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"응? 무슨 차질? 오다가 지갑이라도 떨어트렸어?","JPN":"うん？　なんの問題？　来る途中で財布でも落としたの？","ENG":"Huh? What kind of snag? Did you drop your wallet or something?","TWN":"嗯？什麼狀況？路上把錢包弄丟了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"지갑만 떨어졌으면 다행이네만…","JPN":"落ちたのが財布だけならまだよかったのだが……","ENG":"If only…","TWN":"如果只是弄丟錢包就好了…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나도 떨어졌거든.","JPN":"某も落ちてしまった。","ENG":"I dropped myself.","TWN":"我人也掉下去了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"끄응… 으그긋-","JPN":"ぐぬぬ……ううう～……","ENG":"Errrgh… Oof…","TWN":"哼嗯…呃啊—"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"하아-","JPN":"はあ～","ENG":"*Sigh*","TWN":"哀—"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L1_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"함정도 아니고 뭐가 이렇게 깊어?","JPN":"何これ、罠？　なんでこんなに深いの？","ENG":"Seriously, what is with this hole? It's not a trap, but it's deep as heck.","TWN":"這不是陷阱吧，怎麼這麼深？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"고맙네. 밧줄을 안 가져왔다면 영영 갇힐 뻔했어.","JPN":"助かった。縄を持ってきて正解だったな。永遠にここに閉じ込められるところだった。","ENG":"Much appreciated. If you hadn't brought that rope, I'd be stuck for good.","TWN":"謝謝。如果你沒帶繩子來，我大概會永遠被困在這裡。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"별일이군. 수풀 속에 이런 깊은 구멍이 있다니.","JPN":"茂みの中にこんなに深い穴があるとは、珍しいな。","ENG":"That's odd. A hole this deep hidden under brush?","TWN":"真是稀奇，灌木叢裡竟然有這麼深的洞。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"난 사부가 거기서 아침까지 태연하게 잠을 잤다는 게 더 놀라운데?","JPN":"私は師匠がそこで朝まで平然と寝られたことのほうが驚きだよ。","ENG":"I'm more shocked you were just napping in there until morning.","TWN":"我覺得更奇怪的是，師父你竟然能在裡面睡到天亮？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"도시로 가던 사람이 어쩌다 숲에서 이런 꼴이 된 거야?","JPN":"都市に向かってたんでしょ、どうして森でこんな羽目になったの？","ENG":"How does a guy headed to town end up in this mess in the woods?","TWN":"你不是進城買菜嗎？怎麼會弄成這樣？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"사람을 쫓다가 빠졌다네.","JPN":"人を追いかけていたら落ちてしまった。","ENG":"I was tracking someone and fell.","TWN":"我在追一個人的時候掉進去的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이 산골짜기에서 사람을 봤다고?","JPN":"こんな山奥で人を見かけた？","ENG":"You saw someone? Out here in the mountains?","TWN":"你說在這荒郊野外看到人？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부, 구멍에 빠진 게 창피해서 막 지어내는 거지?","JPN":"師匠、穴に落ちたのが恥ずかしくて嘘ついてるんでしょ。","ENG":"Hold on a sec. Are you making this up because you're ashamed?","TWN":"師父，你是因為掉進洞裡太丟臉才亂編的吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"제자의 신뢰를 잃었군.","JPN":"弟子の信用を失ってしまったな。","ENG":"Seems I've lost my apprentice's trust.","TWN":"看來徒弟不相信我。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"삐진 척하지 말고.","JPN":"拗ねたふりしないの。","ENG":"Oh, don't sulk.","TWN":"你才沒有生氣咧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그런데 이 구멍 낯익지 않아? 어디서 봤던 것 같은…","JPN":"でもこの穴、なんか見覚えがあるよね。どこかで見た気が……","ENG":"But hey, doesn't this hole look familiar? Like I've seen it somewhere before…","TWN":"不過這個洞看起來很眼熟？好像在哪裡見過…"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"다들 이쪽으로 와봐.","JPN":"2人ともこっちに来てみろ。","ENG":"Everyone, over here.","TWN":"大家過來看看。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"다른 구멍을 발견했다.","JPN":"別の穴を見つけた。","ENG":"I found another hole.","TWN":"我發現另一個洞。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이런 곳에 굴이 있다니. 심지어 꽤 깊어.","JPN":"こんなところに洞窟があったんだ。しかもかなり深そう。","ENG":"There's a cave down here? And it's pretty deep.","TWN":"沒想到這裡有洞穴，而且還蠻深的。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사람이 지나가려고 만든 터널 같은데, 평범한 곳은 아니네.","JPN":"人が通るために作ったトンネルみたいだけど、普通の場所じゃないよね。","ENG":"Looks like a tunnel, but not an ordinary one.","TWN":"看起來像是人為挖掘的通道，不是普通的地方。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Right.","TWN":"對。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"침식체가 있다면, 확실히 평범한 곳은 아니지.","JPN":"侵食体がいるということは、確かに普通の場所じゃないな。","ENG":"If C.O.s are lurking, it's definitely not ordinary.","TWN":"有侵蝕體的話，那肯定不是普通的地方。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"다들 조심하게.","JPN":"皆気をつけたまえ。","ENG":"Stay sharp, everyone.","TWN":"大家小心。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"}]`);export{e as default};